	"time"
)

// BackendAxon selects the axon-backed RawBackend. Per TD-030 D3 the on-disk
// shape splits beads from their events: one row per bead in the
// ddx_beads collection, plus one entity per event in the
// ddx_bead_events collection linked back to its bead via event_of.
//
// The implementation in axon_backend.go is an in-process emulation of the
// axon GraphQL surface. It serializes the two collections to JSONL files
// under <dir>/axon/ and acquires a single directory lock around mutations.
// The wire-protocol path (genqlient against a real axon server, per TD-030
// §"Wire transport") is the GA delivery; this RawBackend keeps the same
// two-collection split and OCC-compatible bead row schema so the wire path
// is a contained refactor.
//
// AC §3 ("Behind a feature flag until ddx-3ec0chaos signs off"): NewStore
// only routes to AxonBackend when the operator opts in via
// DDX_AXON_EXPERIMENTAL=1. With the flag unset, beads.backend=axon falls
// through to the JSONL default and a stderr warning is emitted so the
// misconfiguration is visible without breaking the workspace.
const BackendAxon = "axon"

// AxonExperimentalEnv gates whether the axon backend may be selected. The
// flag is intentionally separate from beads.backend so the chaos-test bead
// (ddx-743bc194) can flip operators to axon machine-by-machine without
// editing every project's config.
const AxonExperimentalEnv = "DDX_AXON_EXPERIMENTAL"

// axonSchemaVersion is written into every persisted entity. Schema upgrades
// are handled lazy-on-read until axon FEAT-017 ships native schema
// migration (per TD-030 v1 policy on schema versioning).
const axonSchemaVersion = 1

// AxonDirName is the per-store axon subdirectory under .ddx that holds the
// two-collection snapshot files and the lock dir.
const AxonDirName = "axon"

// AxonBeadsCollection / AxonEventsCollection are the logical collection names
// from TD-030's schema mapping. They are surfaced as the on-disk filenames so
// inspecting the directory tells the operator which collection an entity
// belongs to.
const (
	AxonBeadsCollection  = "ddx_beads"
	AxonEventsCollection = "ddx_bead_events"
)

// AxonBackend stores the bead corpus in axon's two-collection shape.
//
// On WriteAll the backend splits each bead's inline Extra["events"] into one
// entity per event under ddx_bead_events and persists the bead row (sans
// inline events) under ddx_beads. ReadAll re-merges events back into
// Extra["events"] so the higher-level Store and the chaos suite see the
// uniform inline-events shape they expect.
//
// Beads with Extra[events_attachment] set (post-Close externalisation) are
// persisted with their events array empty in axon's events collection. The
// attachment file remains the canonical source for those events so Store's
// existing read path (eventsForBead) keeps working unchanged.
type AxonBackend struct {
	Dir        string
	BeadsFile  string
	EventsFile string
	LockDir    string
	LockWait   time.Duration
}

// Compile-time check: AxonBackend satisfies RawBackend.
var _ RawBackend = (*AxonBackend)(nil)

// NewAxonBackend constructs an axon-backed RawBackend rooted at dir. dir is
// the .ddx directory for the project; collection files and the lock live
// under <dir>/axon/.
func NewAxonBackend(dir string, lockWait time.Duration) *AxonBackend {
	root := filepath.Join(dir, AxonDirName)
	return &AxonBackend{
		Dir:        root,
		BeadsFile:  filepath.Join(root, AxonBeadsCollection+".jsonl"),
		EventsFile: filepath.Join(root, AxonEventsCollection+".jsonl"),
		LockDir:    filepath.Join(root, ".lock"),
		LockWait:   lockWait,
	}
}

// AxonExperimentalEnabled reports whether the operator has opted in to the
// experimental axon backend via DDX_AXON_EXPERIMENTAL=1. NewStore consults
// this before routing beads.backend=axon to AxonBackend.
func AxonExperimentalEnabled() bool {
	switch strings.ToLower(strings.TrimSpace(os.Getenv(AxonExperimentalEnv))) {
	case "1", "true", "yes", "on":
		return true
	}
	return false
}

func (a *AxonBackend) Init() error {
	if err := os.MkdirAll(a.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: axon init dir: %w", err)
	}
	for _, path := range []string{a.BeadsFile, a.EventsFile} {
		f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY, 0o644)
		if err != nil {
			return fmt.Errorf("bead: axon init %s: %w", path, err)
		}
		if err := f.Close(); err != nil {
			return fmt.Errorf("bead: axon close %s: %w", path, err)
		}
	}
	return nil
}

// ReadAll loads bead rows and event entities from disk and re-merges events
// back into each bead's Extra["events"]. Orphan events (event_of pointing at
// a missing bead, e.g. after a partial-write crash) are silently dropped.
func (a *AxonBackend) ReadAll() ([]Bead, error) {
	beads, err := a.readBeadRows()
	if err != nil {
		return nil, err
	}
	events, err := a.readEventEntities()
	if err != nil {
		return nil, err
	}
	// Index beads by id so we can attach events and drop orphans.
	byID := make(map[string]*Bead, len(beads))
	for i := range beads {
		byID[beads[i].ID] = &beads[i]
	}
	// Group events by bead id with exact per-bead capacity so the read path
	// does not repeatedly grow slices while rebuilding the inline shape.
	counts := make(map[string]int, len(events))
	for _, ev := range events {
		if _, ok := byID[ev.beadID]; !ok {
			continue // orphan
		}
		counts[ev.beadID]++
	}
	grouped := make(map[string][]BeadEvent, len(counts))
	for id, count := range counts {
		grouped[id] = make([]BeadEvent, 0, count)
	}
	for _, ev := range events {
		if _, ok := byID[ev.beadID]; !ok {
			continue
		}
		grouped[ev.beadID] = append(grouped[ev.beadID], ev.event)
	}
	for id, evs := range grouped {
		b := byID[id]
		if b.Extra == nil {
			b.Extra = make(map[string]any)
		}
		// Skip beads whose events have been externalised — the attachment file
		// is the canonical source post-close and inlining stale events would
		// duplicate the history.
		if hasEventsAttachment(b) {
			continue
		}
		b.Extra["events"] = encodeEventsForExtra(evs)
	}
	return beads, nil
}

// WriteAll splits inline events from each bead and persists both collections.
// Writes are serialised at the directory-lock layer (WithLock); this method
// rewrites both files in temp+rename style so a crash mid-write leaves the
// previous snapshot intact rather than producing torn rows.
func (a *AxonBackend) WriteAll(beads []Bead) error {
	if err := os.MkdirAll(a.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: axon mkdir: %w", err)
	}
	sort.Slice(beads, func(i, j int) bool { return beads[i].ID < beads[j].ID })

	var beadsBuf, eventsBuf bytes.Buffer
	for _, b := range beads {
		// Extract and strip inline events for the split.
		var events []BeadEvent
		if b.Extra != nil {
			if raw, ok := b.Extra["events"]; ok {
				events = decodeBeadEvents(raw)
			}
		}
		stripped := beadWithoutInlineEvents(b)
		row, err := axonEncodeBead(stripped)
		if err != nil {
			return fmt.Errorf("bead: axon marshal %s: %w", b.ID, err)
		}
		beadsBuf.Write(row)
		beadsBuf.WriteByte('\n')

		for i, ev := range events {
			data, err := axonEncodeEvent(b.ID, i, ev)
			if err != nil {
				return fmt.Errorf("bead: axon marshal event %s/%d: %w", b.ID, i, err)
			}
			eventsBuf.Write(data)
			eventsBuf.WriteByte('\n')
		}
	}

	// Write events first so a crash between the two writes leaves orphan
	// events (which ReadAll silently drops) rather than a bead row whose
	// events have not landed yet — favouring the safer side of the partial-
	// write window for an audit log.
	if err := writeAtomicFile(a.EventsFile, eventsBuf.Bytes()); err != nil {
		return fmt.Errorf("bead: axon write events: %w", err)
	}
	if err := writeAtomicFile(a.BeadsFile, beadsBuf.Bytes()); err != nil {
		return fmt.Errorf("bead: axon write beads: %w", err)

package axon

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/gorilla/websocket"
)

const graphqlWSSubprotocol = "graphql-transport-ws"

const changeEventsSubscription = `subscription ChangeEvents($projectID: ID!) { changeEvents(projectID: $projectID) { ...ChangeEventFields } }`

// ChangeEvent mirrors the GraphQL subscription payload for lifecycle updates.
type ChangeEvent struct {
	EventID   string    `json:"eventID"`
	BeadID    string    `json:"beadID"`
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary"`
	Body      string    `json:"body"`
	Actor     string    `json:"actor"`
	Timestamp time.Time `json:"timestamp"`
}

// ChangeEventFromLifecycle converts the local bead lifecycle event into the
// Axon GraphQL subscription shape.
func ChangeEventFromLifecycle(src bead.LifecycleEvent) ChangeEvent {
	return ChangeEvent{
		EventID:   src.EventID,
		BeadID:    src.BeadID,
		Kind:      src.Kind,
		Summary:   src.Summary,
		Body:      src.Body,
		Actor:     src.Actor,
		Timestamp: src.Timestamp,
	}
}

// ToLifecycleEvent converts the GraphQL subscription payload back into the
// local bead lifecycle model.
func (c ChangeEvent) ToLifecycleEvent() bead.LifecycleEvent {
	return bead.LifecycleEvent{
		EventID:   c.EventID,
		BeadID:    c.BeadID,
		Kind:      c.Kind,
		Summary:   c.Summary,
		Body:      c.Body,
		Actor:     c.Actor,
		Timestamp: c.Timestamp,
	}
}

// SubscriptionTransport is the minimal GraphQL-over-WebSocket transport used
// by the Axon client subscription path.
type SubscriptionTransport interface {
	Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error)
}

// DualTransport lets callers combine a query transport and a subscription
// transport behind the same Client value.
type DualTransport struct {
	Queries       Transport
	Subscriptions SubscriptionTransport
}

// Query forwards GraphQL queries and mutations to the query transport.
func (d DualTransport) Query(ctx context.Context, query string, variables map[string]any, response any) error {
	if d.Queries == nil {
		return fmt.Errorf("axon: query transport not configured")
	}
	return d.Queries.Query(ctx, query, variables, response)
}

// Subscribe forwards GraphQL subscriptions to the subscription transport.
func (d DualTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
	if d.Subscriptions == nil {
		return nil, fmt.Errorf("axon: subscription transport not configured")
	}
	return d.Subscriptions.Subscribe(ctx, query, variables)
}

// WebSocketSubscriptionTransport speaks the graphql-transport-ws protocol.
type WebSocketSubscriptionTransport struct {
	URL         string
	Header      http.Header
	Dialer      *websocket.Dialer
	InitPayload map[string]any
}

// NewWebSocketSubscriptionTransport creates a websocket subscription transport
// rooted at url. The URL may be ws://, wss://, http://, or https://.
func NewWebSocketSubscriptionTransport(url string) *WebSocketSubscriptionTransport {
	return &WebSocketSubscriptionTransport{URL: url}
}

// Query is unsupported on the websocket subscription transport.
func (t *WebSocketSubscriptionTransport) Query(context.Context, string, map[string]any, any) error {
	return fmt.Errorf("axon: websocket subscription transport does not execute queries")
}

// Subscribe opens a GraphQL WebSocket subscription and streams raw payloads
// from graphql-transport-ws next messages.
func (t *WebSocketSubscriptionTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
	url := normalizeWebSocketURL(strings.TrimSpace(t.URL))
	if url == "" {
		return nil, fmt.Errorf("axon: websocket subscription url is required")
	}

	dialer := websocket.DefaultDialer
	if t.Dialer != nil {
		dialer = t.Dialer
	}
	if len(dialer.Subprotocols) == 0 {
		dialer = cloneDialer(dialer)
		dialer.Subprotocols = []string{graphqlWSSubprotocol}
	}

	header := cloneHeader(t.Header)
	conn, _, err := dialer.DialContext(ctx, url, header)
	if err != nil {
		return nil, fmt.Errorf("axon: websocket dial: %w", err)
	}

	closed := make(chan struct{})
	var closeOnce sync.Once
	cleanup := func() {
		closeOnce.Do(func() {
			close(closed)
			_ = conn.Close()
		})
	}
	go func() {
		select {
		case <-ctx.Done():
			cleanup()
		case <-closed:
		}
	}()

	if conn.Subprotocol() != "" && conn.Subprotocol() != graphqlWSSubprotocol {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subprotocol mismatch: got %q want %q", conn.Subprotocol(), graphqlWSSubprotocol)
	}

	if err := conn.WriteJSON(graphqlWSMessage{Type: "connection_init", Payload: mustJSON(t.InitPayload)}); err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket connection_init: %w", err)
	}

	for {
		var msg graphqlWSMessage
		if err := conn.ReadJSON(&msg); err != nil {
			cleanup()
			return nil, fmt.Errorf("axon: websocket ack: %w", err)
		}
		switch msg.Type {
		case "connection_ack":
			goto subscribed
		case "ping":
			_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
		case "error":
			cleanup()
			return nil, fmt.Errorf("axon: websocket connection error")
		}
	}

subscribed:
	subPayload, err := json.Marshal(map[string]any{
		"query":     query,
		"variables": variables,
	})
	if err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subscribe payload: %w", err)
	}
	if err := conn.WriteJSON(graphqlWSMessage{ID: "1", Type: "subscribe", Payload: subPayload}); err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subscribe: %w", err)
	}

	out := make(chan json.RawMessage)
	go func() {
		defer close(out)
		defer cleanup()
		for {
			var msg graphqlWSMessage
			if err := conn.ReadJSON(&msg); err != nil {
				return
			}
			switch msg.Type {
			case "next":
				if len(msg.Payload) == 0 {
					continue
				}
				payload := append(json.RawMessage(nil), msg.Payload...)
				select {
				case out <- payload:
				case <-ctx.Done():
					return
				}
			case "complete":
				return
			case "ping":
				_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
			case "error":
				return
			}
		}
	}()

	return out, nil
}

type graphqlWSMessage struct {
	ID      string          `json:"id,omitempty"`
	Type    string          `json:"type"`
	Payload json.RawMessage `json:"payload,omitempty"`
}

type changeEventsEnvelope struct {
	Data struct {
		ChangeEvents *ChangeEvent `json:"changeEvents,omitempty"`
	} `json:"data"`
}

func normalizeWebSocketURL(url string) string {
	switch {
	case strings.HasPrefix(url, "http://"):
		return "ws://" + strings.TrimPrefix(url, "http://")
	case strings.HasPrefix(url, "https://"):
		return "wss://" + strings.TrimPrefix(url, "https://")
	default:
		return url
	}
}

func cloneHeader(src http.Header) http.Header {
	if len(src) == 0 {
		return http.Header{}
	}
	dst := make(http.Header, len(src))
	for k, values := range src {
		dst[k] = append([]string(nil), values...)
	}
	return dst
}

func cloneDialer(src *websocket.Dialer) *websocket.Dialer {
	if src == nil {
		return &websocket.Dialer{}
	}
	cp := *src
	cp.Subprotocols = append([]string(nil), src.Subprotocols...)
	return &cp

package axon

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/gorilla/websocket"
	"github.com/stretchr/testify/require"
)

func TestAxonSubscription_ChangeEventsStream(t *testing.T) {
	t.Parallel()

	errCh := make(chan error, 1)
	upgrader := websocket.Upgrader{
		CheckOrigin: func(*http.Request) bool { return true },
	}

	ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		conn, err := upgrader.Upgrade(w, r, nil)
		if err != nil {
			select {
			case errCh <- err:
			default:
			}
			return
		}
		defer conn.Close()

		fail := func(err error) {
			if err == nil {
				return
			}
			select {
			case errCh <- err:
			default:
			}
		}

		var msg graphqlWSMessage
		if err := conn.ReadJSON(&msg); err != nil {
			fail(err)
			return
		}
		if msg.Type != "connection_init" {
			fail(&unexpectedProtocolError{got: msg.Type, want: "connection_init"})
			return
		}

		if err := conn.WriteJSON(graphqlWSMessage{Type: "connection_ack"}); err != nil {
			fail(err)
			return
		}

		if err := conn.ReadJSON(&msg); err != nil {
			fail(err)
			return
		}
		if msg.Type != "subscribe" {
			fail(&unexpectedProtocolError{got: msg.Type, want: "subscribe"})
			return
		}

		var payload struct {
			Query     string         `json:"query"`
			Variables map[string]any `json:"variables"`
		}
		if err := json.Unmarshal(msg.Payload, &payload); err != nil {
			fail(err)
			return
		}
		if payload.Query != changeEventsSubscription {
			fail(&unexpectedStringError{got: payload.Query, want: changeEventsSubscription})
			return
		}
		if got := payload.Variables["projectID"]; got != "project-123" {
			fail(&unexpectedStringError{got: toString(got), want: "project-123"})
			return
		}

		events := []ChangeEvent{
			{
				EventID:   "evt-1",
				BeadID:    "bead-1",
				Kind:      "created",
				Summary:   "bead created",
				Body:      "body-1",
				Actor:     "tester",
				Timestamp: time.Unix(10, 0).UTC(),
			},
			{
				EventID:   "evt-2",
				BeadID:    "bead-1",
				Kind:      "updated",
				Summary:   "bead updated",
				Body:      "body-2",
				Actor:     "tester",
				Timestamp: time.Unix(20, 0).UTC(),
			},
		}
		for _, evt := range events {
			payload, err := json.Marshal(map[string]any{
				"data": map[string]any{
					"changeEvents": evt,
				},
			})
			if err != nil {
				fail(err)
				return
			}
			if err := conn.WriteJSON(graphqlWSMessage{ID: "1", Type: "next", Payload: payload}); err != nil {
				fail(err)
				return
			}
		}
		if err := conn.WriteJSON(graphqlWSMessage{ID: "1", Type: "complete"}); err != nil {
			fail(err)
		}
	}))
	t.Cleanup(ts.Close)

	wsURL := "ws" + strings.TrimPrefix(ts.URL, "http")
	client := NewClient(DualTransport{
		Queries:       noopTransport{},
		Subscriptions: NewWebSocketSubscriptionTransport(wsURL),
	})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	t.Cleanup(cancel)

	stream, err := client.SubscribeChangeEvents(ctx, "project-123")
	require.NoError(t, err)

	var got []ChangeEvent
	for evt := range stream {
		got = append(got, evt)
	}
	require.Len(t, got, 2)
	require.Equal(t, "evt-1", got[0].EventID)
	require.Equal(t, "bead-1", got[0].BeadID)
	require.Equal(t, "created", got[0].Kind)
	require.Equal(t, "bead created", got[0].Summary)
	require.Equal(t, "evt-2", got[1].EventID)
	require.Equal(t, "updated", got[1].Kind)

	select {
	case err := <-errCh:
		require.NoError(t, err)
	default:
	}
}

type unexpectedProtocolError struct {
	got  string
	want string
}

func (e *unexpectedProtocolError) Error() string {
	return "unexpected protocol message type: got " + e.got + " want " + e.want
}

type unexpectedStringError struct {
	got  string
	want string
}

func (e *unexpectedStringError) Error() string {
	return "unexpected string: got " + e.got + " want " + e.want
}

func toString(v any) string {
	switch x := v.(type) {
	case string:
		return x
	case nil:
		return ""
	default:
		data, _ := json.Marshal(x)
		return string(data)
	}
}

